tracing-subscriber = { version = "0.3", features = ["std", "fmt", "reload", "registry"] }",
  "main.rs": "use std::fs::OpenOptions;
use tracing::{debug, error, info, warn};
use tracing_subscriber::{filter::LevelFilter, fmt, prelude::*, reload};

fn main() {
    // 1. Setup the Log File
    let file = OpenOptions::new()
        .create(true)
        .write(true)
        .truncate(true)
        .open("logfile.log")
        .expect("Failed to open logfile.log");

    // 2. Setup Reloadable Filters
    // Instead of wrapping the entire layer, we wrap the *Leaf Filter* (LevelFilter).
    // This returns a Layer (which acts as a filter) and a Handle to modify it.

    // Console defaults to INFO
    let (console_filter_layer, console_handle) = 
        reload::Layer::new(LevelFilter::INFO);

    // File defaults to ERROR
    let (file_filter_layer, file_handle) = 
        reload::Layer::new(LevelFilter::ERROR);

    // 3. Construct the Subscriber
    let subscriber = tracing_subscriber::registry()
        .with(
            // Layer 1: Console
            fmt::layer()
                .with_target(false)
                .with_ansi(true)
                // Important: Attach the reloadable filter to this specific layer
                .with_filter(console_filter_layer),
        )
        .with(
            // Layer 2: File
            fmt::layer()
                .with_writer(move || file.try_clone().expect("failed to clone file handle"))
                .with_ansi(false)
                // Important: Attach the reloadable filter to this specific layer
                .with_filter(file_filter_layer),
        );

    // 4. Initialize (Must only be done ONCE per program, not in the loops/threads)
    tracing::subscriber::set_global_default(subscriber)
        .expect("setting default subscriber failed");

    // --- DEMONSTRATION ---

    println!("\n--- Phase 1: Console=INFO, File=ERROR ---");
    info!("1. This is INFO: Visible on Console, NOT on File.");
    error!("2. This is ERROR: Visible on Console AND File.");
    debug!("3. This is DEBUG: Invisible everywhere.");

    // DYNAMIC CHANGE 1: Enable DEBUG on Console only
    println!("\n--- Phase 2: Switching Console to DEBUG ---");
    console_handle.modify(|filter| *filter = LevelFilter::DEBUG)
        .expect("Failed to modify console filter");

    debug!("4. This is DEBUG: Now visible on Console, still NOT on File.");
    info!("5. This is INFO: Still visible on Console, still NOT on File.");

    // DYNAMIC CHANGE 2: Enable INFO on File
    println!("\n--- Phase 3: Switching File to INFO ---");
    file_handle.modify(|filter| *filter = LevelFilter::INFO)
        .expect("Failed to modify file filter");

    info!("6. This is INFO: Now visible on Console AND File.");

    println!("\nDone. Check contents of 'logfile.log'.");
}"
}
